Uploaded file: NodeKit governed Change Story
{
  "change": {
    "affectedSystems": [
      "NodeKit factory",
      "Casca FDE Deployment Lab",
      "FounderQuest Agentic RL research lab",
      "Founder Quest Graph product",
      "NodeSlide presentation pipeline",
      "Feature Proof Studio video pipeline",
      "Chrome/CDP publication workflow"
    ],
    "alternatives": [
      {
        "name": "Build another general agent runtime",
        "rejectedBecause": "Existing runtimes already cover generic orchestration; the missing value is application composition, artifact governance, and certification."
      },
      {
        "name": "Publish a concept announcement before product proof",
        "rejectedBecause": "It would make the deck the source of truth instead of a projection of executed evidence."
      }
    ],
    "approvalBoundaries": {
      "destructiveCleanup": "not_in_scope",
      "directMessagesRepliesOrPaidPromotion": "prohibited",
      "exactPublicCampaign": "authorized",
      "paidLiveProvider": "authorized",
      "productionDeployment": "authorized"
    },
    "audience": [
      "agent builders",
      "applied AI researchers",
      "forward-deployed engineers",
      "technical founders and investors"
    ],
    "changeType": "release-campaign",
    "communicationJob": "By the end, a technical reviewer should understand that NodeKit is a portable application contract and verification path, see exactly which product slices have passed which gates, and know where the remaining release boundaries are local, blocked, or pending publication.",
    "decision": [
      "Use one thin NodeKit manifest, filesystem-discovered capabilities, composed evaluations, and content-addressed proof receipts.",
      "Prove the system through independent generated applications and preserve failed gates as first-class evidence.",
      "Make the launch itself a governed NodeKit workflow whose public claims resolve to exact receipts."
    ],
    "honestLimitations": [
      "NodeKit v0.2.0 is source-released on GitHub; npm publication is blocked by registry authentication.",
      "The Casca lab is local-ready, not production-proven.",
      "The current Agentic RL lab trains a deterministic behavior-cloning baseline; it does not perform gradient-based reinforcement learning.",
      "Founder Quest Graph is production-proven only as a synthetic, read-only workflow with no durable writes or remote Neo4j writes; it does not prove any external approval."
    ],
    "id": "nodekit-proof-campaign-2026-07-20",
    "nextMilestone": "Regenerate the evidence-bound deck and walkthrough from the verified Founder Quest production receipt, then publish only the exact approved campaign and preserve the resulting public-URL receipts.",
    "presentationTier": 4,
    "previousState": [
      "Agent application scaffolding, runtime, domain evaluation, browser QA, and release evidence were rebuilt manually per project.",
      "A generated application could appear complete without proving that its benchmark, product, and release paths shared the same implementation."
    ],
    "requiredProof": [
      "exact commits and application/config hashes",
      "no-key deterministic factory acceptance",
      "strict paid-provider receipts with no fallback",
      "browser journeys with console and network health",
      "exact deployment identity and fresh-user production proof where claimed",
      "editable deck export and reopen verification",
      "public URL verification and distribution receipts"
    ],
    "schemaVersion": "nodekit.change-story/v1",
    "title": "NodeKit launches NodeKit through proof-carrying product work",
    "userPain": [
      "Empty-directory to proof required repeated repository-specific coordination.",
      "Polished demos could outrun their actual runtime, browser, deployment, or artifact evidence."
    ]
  },
  "claims": {
    "claims": [
      {
        "evidenceIds": [
          "E1_FACTORY_ACCEPTANCE",
          "E2_NODEKIT_RELEASE"
        ],
        "id": "C1_FACTORY_ACCEPTANCE",
        "limitations": [
          "The timed acceptance is deterministic and local; it is not a production deployment benchmark.",
          "The npm registry package is not published."
        ],
        "scope": {
          "commit": "ef23bb0d630c265d21be5443138cd1a5b769ed8c",
          "tag": "v0.2.0"
        },
        "status": "measured",
        "text": "NodeKit v0.2.0 generated, installed, compiled, checked, demonstrated, evaluated, benchmarked, and proof-verified both the Agentic RL and SMB-lending presets from empty directories in 37.221 seconds."
      },
      {
        "evidenceIds": [
          "E3_CASCA_RELEASE",
          "E4_CASCA_BROWSER",
          "E5_CASCA_LIVE"
        ],
        "id": "C2_CASCA_LOCAL_PROOF",
        "limitations": [
          "The application is synthetic and unaffiliated with Casca.",
          "Deployment remains an explicitly missing release gate."
        ],
        "scope": {
          "commit": "6c8d7d9f81810509240fe0b2352453bfa04ac924",
          "releaseLevel": "local-ready"
        },
        "status": "verified",
        "text": "The Casca FDE Deployment Lab passed its deterministic, live-provider, adversarial browser, reload, export, and identity-binding gates on one exact commit."
      },
      {
        "evidenceIds": [
          "E6_RL_RELEASE",
          "E7_RL_HELDOUT",
          "E11_RL_CI"
        ],
        "id": "C3_RL_LOCAL_BASELINE",
        "limitations": [
          "This is not policy-gradient RL, preference optimization, online learning, GPU training, or a weight update.",
          "The two-task heldout set is diagnostic and too small for generalization claims."
        ],
        "scope": {
          "commit": "d6826837920d828edd4d7026c4fc17388f27b8b9",
          "releaseLevel": "local-learning-baseline-ready"
        },
        "status": "verified",
        "text": "The Agentic RL research lab exports step trajectories, trains a deterministic behavior-cloning baseline, blocks nine adversarial reward attacks, and evaluates a label-free process-separated heldout split."
      },
      {
        "evidenceIds": [
          "E8_RL_LIVE_BLOCKED"
        ],
        "id": "C4_RL_LIVE_ROUTE",
        "limitations": [
          "The live baseline produced no candidate completions and therefore proves enforcement, not model quality."
        ],
        "scope": {
          "commit": "353d825767682eaacda989551270747a95bcffc4",
          "releaseLevel": "blocked"
        },
        "status": "observed",
        "text": "The preregistered Agentic RL live-model baseline failed closed when the Azure-only, zero-data-retention OpenRouter route returned HTTP 404; no retry, fallback, token usage, or cost was accepted."
      },
      {
        "evidenceIds": [
          "E12_FOUNDER_QUEST_PRODUCTION",
          "E13_FOUNDER_QUEST_RELEASE"
        ],
        "id": "C5_FOUNDER_QUEST_PRODUCT",
        "limitations": [
          "The journey is synthetic and read-only; no durable writes or remote Neo4j writes occur.",
          "The 15 hosted checks and four isolated browser contexts prove this bounded production journey, not government, bank, legal, tax, regulatory, or other external approval."
        ],
        "scope": {
          "appHash": "973ea7cbd8039e963bab1ff604bc0180bf0457f9a334b9b9dc0f77062f103e20",
          "artifactManifestHashesVerified": 25,
          "commit": "dc5fba2467576d5ded3d3ac6bf4d142316410c86",
          "configHash": "973ea7cbd8039e963bab1ff604bc0180bf0457f9a334b9b9dc0f77062f103e20",
          "evidenceCommit": "04579137a85f4ce18db61e6e7c0f25ff7b1d42b6",
          "graphRevision": "ng1_c9334138",
          "hostedChecksPassed": 15,
          "hostedDeploymentCertified": true,
          "isolatedBrowserContexts": 4,
          "productionReceiptDigest": "023154fb77698b8704932ccaa9a0736a252a6de8b1ea46da3f76675ffac9f49c",
          "productionUrl": "https://founder-quest-graph.vercel.app/",
          "releaseAuditIssues": 0,
          "releaseLevel": "production-certified",
          "releaseReady": true,
          "testsPassed": 18,
          "unifiedReleaseReceiptDigest": "3366a2466bfed64e07c70324babbb9d2eb369965e7e1930c9f00909b199bb5a5"
        },
        "status": "verified",
        "text": "Founder Quest Graph provides a read-only synthetic quest rail, bounded graph workspace, source-backed answer panel, and proof surface on an exact production revision that passed all 15 hosted checks."
      },
      {
        "evidenceIds": [
          "E9_ANTHROPIC_GRANT_SOURCE"
        ],
        "id": "C6_ANTHROPIC_GRANT_CASE",
        "limitations": [
          "NodeKit is not affiliated with or endorsed by Anthropic and has not received this grant."
        ],
        "scope": {
          "retrievedAt": "2026-07-20"
        },
        "status": "verified",
        "text": "NodeKit uses Anthropic's rare-disease research grants as an independent external scenario for mapping current research, novelty, execution, evaluation, and application readiness."
      },
      {
        "evidenceIds": [],
        "id": "C7_RECURSIVE_LAUNCH",
        "limitations": [
          "Past tense is prohibited until all artifact, publication, and public-URL receipts exist."
        ],
        "scope": {},
        "status": "planned",
        "text": "NodeKit directed the research, product proofs, editable deck, walkthrough video, and browser-assisted publication of this campaign."
      },
      {
        "evidenceIds": [
          "E10_GRAPH_OF_LOOPS_SOURCE"
        ],
        "id": "C8_GRAPH_OF_LOOPS_FRAME",
        "limitations": [
          "The loop and graph mechanics predate the current phrase; NodeKit claims an application of the framing, not ownership of the underlying architecture."
        ],
        "scope": {
          "retrievedAt": "2026-07-20"
        },
        "status": "verified",
        "text": "NodeKit applies Carlos E. Perez's graph-of-loops framing to a proof-carrying product workflow, with explicit attribution to Perez's essay and Peter Steinberger's originating prompt."
      },
      {
        "evidenceIds": [
          "E14_FOUNDER_QUEST_VIDEO_PROOF"
        ],
        "id": "C9_MEDIA_PROOF",
        "limitations": [
          "Both videos use silent AAC tracks and burned-in captions.",
          "The walkthrough proves one synthetic read-only production journey, not an external outcome or publication."
        ],
        "scope": {
          "campaignCommit": "f002870ab08faaf992677589216d4384211fd1e1",
          "technicalSha256": "b3b10fcc7ed9bce329aa608ae42294886d6db9b6ff1882bd34e2873ffc1b7ea1",
          "verticalSha256": "7733c39be6493807459c018931130ccbfed02a6d27659c5a28d60e971591b31d"
        },
        "status": "verified",
        "text": "NodeKit produced and verified an 83-second vertical walkthrough and a 180-second technical walkthrough from the exact Founder Quest production capture, with burned-in narrative text and content-addressed receipts."
      }
    ],
    "schemaVersion": "nodekit.claim-ledger/v1"
  },
  "limitations": {
    "limitations": [
      {
        "id": "L1_NPM_AUTH",
        "severity": "release-boundary",
        "text": "NodeKit v0.2.0 is distributed through its GitHub source release because npm authentication returned E401."
      },
      {
        "id": "L2_CASCA_LOCAL_ONLY",
        "severity": "release-boundary",
        "text": "The Casca FDE lab is local-ready and browser-proven on loopback, but not hosted or production-proven."
      },
      {
        "id": "L3_RL_SCOPE",
        "severity": "scientific-boundary",
        "text": "The Agentic RL lab currently implements behavior cloning and protected evaluation, not reinforcement-learning weight optimization."
      },
      {
        "id": "L4_RL_LIVE_BLOCKED",
        "severity": "provider-boundary",
        "text": "The preregistered Azure-only/ZDR live baseline received HTTP 404 and was not retried with a weaker privacy or routing policy."
      },
      {
        "id": "L5_FOUNDERQUEST_SYNTHETIC",
        "severity": "product-boundary",
        "text": "Founder Quest Graph uses a fictional California LLC in a read-only production journey. It performs no durable writes or remote Neo4j writes. Its receipts prove the bounded hosted workflow, never government, bank, insurance, payment-provider, legal, tax, regulatory, or other external approval."
      },
      {
        "id": "L6_NO_ANTHROPIC_AFFILIATION",
        "severity": "public-claim-boundary",
        "text": "The Anthropic grant is an independent external scenario; NodeKit is not affiliated with or endorsed by Anthropic and has not received the grant."
      },
      {
        "id": "L7_GRAPH_OF_LOOPS_ATTRIBUTION",
        "severity": "source-boundary",
        "text": "The public campaign attributes the graph-of-loops framing to Carlos E. Perez's essay and Peter Steinberger's originating prompt, while recognizing that directed graphs, state machines, and multi-agent orchestration predate the current terminology."
      }
    ],
    "schemaVersion": "nodekit.limitations/v1"
  }
}
